写 fix(c) 函数映射易混淆字母→数字，遍历标准化并判断是否全数字。

```cpp
#include <bits/stdc++.h>
using namespace std;
char fix(char c) {
    if (c == 'O') return '0';
    if (c == 'l' || c == 'I') return '1';
    if (c == 'Z') return '2';
    if (c == 'S') return '5';
    if (c == 'B') return '8';
    return c;
}
int main() {
    int n, cnt = 0;
    cin >> n;
    while (n--) {
        string s; cin >> s;
        bool ok = true;
        for (int i = 0; i < s.size(); i++) {
            s[i] = fix(s[i]);
            if (s[i] < '0' || s[i] > '9') ok = false;
        }
        if (ok) cnt++;
    }
    cout << cnt << endl;
    return 0;
}
```

枚举 VIP、普通票数量，检查剩余能否被10整除且≥10。经典枚举法。

```cpp
#include <bits/stdc++.h>
using namespace std;
int main() {
    int n, cnt = 0;
    cin >> n;
    for (int v = 1; v * 50 <= n; v++)
        for (int p = 1; p * 30 <= n; p++) {
            int rest = n - v * 50 - p * 30;
            if (rest >= 10 && rest % 10 == 0) cnt++;
        }
    cout << cnt << endl;
    return 0;
}
```

枚举大图中每个左上角，四重循环检测 a×b 区域是否完全匹配小图。

```cpp
#include <bits/stdc++.h>
using namespace std;
int main() {
    int n, m, a, b, g[55][55], p[55][55], cnt = 0;
    cin >> n >> m;
    for (int i = 0; i < n; i++)
        for (int j = 0; j < m; j++) cin >> g[i][j];
    cin >> a >> b;
    for (int i = 0; i < a; i++)
        for (int j = 0; j < b; j++) cin >> p[i][j];
    for (int i = 0; i + a <= n; i++)
        for (int j = 0; j + b <= m; j++) {
            bool ok = 1;
            for (int x = 0; x < a && ok; x++)
                for (int y = 0; y < b; y++)
                    if (g[i+x][j+y] != p[x][y]) { ok = 0; break; }
            if (ok) cnt++;
        }
    cout << cnt << endl;
    return 0;
}
```

结构体+自定义 cmp：身高降序→体重升序→成绩升序→姓名升序。浮点成绩乘 10 转 int 避免精度。

```cpp
#include <bits/stdc++.h>
using namespace std;
struct Stu { string nm; int h, w, r; } a[1005];
bool cmp(Stu x, Stu y) {
    if (x.h != y.h) return x.h > y.h;
    if (x.w != y.w) return x.w < y.w;
    if (x.r != y.r) return x.r < y.r;
    return x.nm < y.nm;
}
int main() {
    int n;
    cin >> n;
    for (int i = 0; i < n; i++) {
        double t;
        cin >> a[i].nm >> a[i].h >> a[i].w >> t;
        a[i].r = t * 10 + 0.5;  // 转整数
    }
    sort(a, a + n, cmp);
    for (int i = 0; i < n; i++) cout << a[i].nm << endl;
    return 0;
}
```
